/************************************************/
void
Chemgrid_Score::input_parameters(Parameter_Reader & parm, bool & primary_score,
                                 bool & secondary_score)
{
    // kxr Chemgrid score: Alternate Scoring Scheme for Electrostatics
    // Solvation and Sterics 
    // vdw calc. from chemgrids; electrostatics from DelPhi phimaps
    // various solvation models available see documentation

    string          tmp;

    use_primary_score = false;
    use_secondary_score = false;
    use_chemgrid_score = false;
    use_conf_entropy = false;
    add_ligand_internal = false;
    use_delphi_score = false;
    use_solv_score = false;
    total_ligand_dsolv = false;
    use_odm_score = false;
    use_recep_dsolv = false;
    write_atomic_energy = false;
    redist_pos_desol = false;


    cout << "\nDock3.5 Score Parameters" << endl;
    cout <<
        "------------------------------------------------------------------------------------------"
        << endl;

    if (!primary_score) {
        tmp = parm.query_param("dock3.5_score_primary", "no", "yes no");
        if (tmp == "yes")
            use_primary_score = true;
        else
            use_primary_score = false;

        primary_score = use_primary_score;
    }

    if (!secondary_score) {
        //tmp = parm.query_param("dock3.5_score_secondary", "no", "yes no");
        tmp = "no";
        if (tmp == "yes")
            use_secondary_score = true;
        else
            use_secondary_score = false;

        secondary_score = use_secondary_score;
    }


    if (use_primary_score || use_secondary_score)
        energy_score = 1;
    else
        energy_score = 0;

    if (energy_score == 1) {

        Chemgrid_Score::chem_grid = new Chemgrid_Grid();

        tmp = parm.query_param("dock3.5_vdw_score", "yes", "yes no");
        if (tmp == "yes") {
            use_chemgrid_score = true;
            chem_grid->file_prefix = parm.query_param("dock3.5_grd_prefix", "chem5");
        } else
            cout << " Warning: Steric interaction will not be calculated!!! " <<
                endl;

        // option to read in Delphi grids kxr 041305
        tmp = parm.query_param("dock3.5_electrostatic_score", "yes", "yes no");
        if (tmp == "yes") {
            use_delphi_score = true;
            interpol_method = 2;        // 1 for Demer method, 2 for dock3554 
        } else
            cout <<
                " Warning: Electrostatic interaction will not be calculated!!! "
                << endl;

        // silence conformational entropy for dock6 release
        // tmp =
        // parm.query_param("dock3.5_conformational_entropy_score","no","yes
        // no");
        // if(tmp == "yes") {
        // use_conf_entropy = true;
        // }

        // option to add ligand internal energy to score kxr 010506
        tmp =
            parm.query_param("dock3.5_ligand_internal_energy", "no", "yes no");
        if (tmp == "yes") {
            add_ligand_internal = true;
        }

        tmp =
            parm.query_param("dock3.5_ligand_desolvation_score", "no",
                             "no total volume");
        if (tmp == "total") {
            use_solv_score = true;
            total_ligand_dsolv = true;
        } else if (tmp == "volume") {
            use_solv_score = true;
            if (use_solv_score) {
                chem_grid->solv_file_prefix =
                    parm.query_param("dock3.5_solvent_occlusion_file",
                                     "solvmap");
                tmp = parm.
                    query_param("dock3.5_redistribute_positive_desolvation",
                                "no", "no yes");
                if (tmp == "yes")
                    redist_pos_desol = true;
            }
        }


        // Temporarily disabled by srb on December 4, 2006
        // See the cvs log for the email thread.
        //tmp = parm.query_param("dock3.5_occupancy_desolvation_score", "no",
        //                     "no yes");
        //if (tmp == "yes") {
        //    use_solv_score = true;
        //    use_odm_score = true;
        //    use_recep_dsolv = true; 
        //}

        tmp = parm.query_param("dock3.5_receptor_desolvation_score", "no",
                             "yes no");
        if (tmp == "yes") {
            use_solv_score = true;
            use_recep_dsolv = false;
            cout <<
                " Warning: Receptor desolvation not functional. Only ligand desolvation will be calculated"
                << endl;
            use_odm_score = false;
        }


        tmp =
            parm.query_param("dock3.5_write_atomic_energy_contrib", "no",
                             "yes no");
        if (tmp == "yes")
            write_atomic_energy = true;


        vdw_scale =
            atof(parm.query_param("dock3.5_score_vdw_scale", "1").c_str());
        if (vdw_scale <= 0.0) {
            bool            off;
            off =
                (parm.
                 query_param("dock3.5_score_turn_off_vdw", "yes",
                             "yes no") == "yes") ? true : false;
            if (!off) {
                cout <<
                    "ERROR: Parameter must be a float greater than zero.  Program will terminate."
                    << endl;
                exit(0);
            }
        }
        es_scale =
            atof(parm.query_param("dock3.5_score_es_scale", "1").c_str());
        if (es_scale <= 0.0) {
            bool            off;
            off =
                (parm.
                 query_param("dock3.5_score_turn_off_es", "yes",
                             "yes no") == "yes") ? true : false;
            if (!off) {
                cout <<
                    "ERROR: Parameter must be a float greater than zero.  Program will terminate."
                    << endl;
                exit(0);
            }
        }

        use_score = true;

    }
}


/************************************************/
void
Chemgrid_Score::initialize(AMBER_TYPER & typer)
{

    if (energy_score == 1) {

        cout << "Initializing Dock3.5 Score Routines..." << endl;

        if (use_chemgrid_score)
            chem_grid->read_chm_grid();
        // else
        // read_nrg_grid(); 

        if (use_delphi_score) {
            chem_grid->read_phi_grid();
            if (interpol_method == 1)
                chem_grid->phi_corner_coords();    // Read DelPhi grid kxr
        }

        if (use_solv_score && !total_ligand_dsolv && !use_odm_score)    // ligand 
                                                                        // desolvation 
                                                                        // only 
                                                                        // kxr
            chem_grid->read_solv_grid();

        if (use_solv_score && !total_ligand_dsolv && use_recep_dsolv)   // DelPhi 
                                                                        // computed 
                                                                        // receptor 
                                                                        // desolvation 
                                                                        // kxr
            chem_grid->read_rdsol_grid();

        if (use_solv_score && use_odm_score)
            chem_grid->read_odm_grid();    // Occupancy desolvation score kxr

        init_vdw_energy(typer, chem_grid->att_exp, chem_grid->rep_exp);
        chem_grid->calc_corner_coords();
        use_score = true;

    } else
        use_score = false;


}
/************************************************/
// Read CHEMGRID generated vdw and elec. grids 
// Used by dock3.5.54 kxr 
void
Chemgrid_Grid::read_chm_grid()
{
    string          fname;
    int             i,
                    j;

    fname = file_prefix + ".cmg";
    grid_in = fopen(fname.c_str(), "rb");

    if (grid_in == NULL) {
        cout << "\n\nCould not open " << fname <<
            " for reading chemgrids.  Program will terminate." << endl << endl;
        exit(0);
    }

    cout << " Reading chemgrids from " << fname << endl;

    fread(&size, sizeof(int), 1, grid_in);
    fread(&spacing, sizeof(float), 1, grid_in);
    fread(origin, sizeof(float), 3, grid_in);
    fread(span, sizeof(int), 3, grid_in);

    fread(&atom_model, sizeof(int), 1, grid_in);
    fread(&att_exp, sizeof(int), 1, grid_in);
    fread(&rep_exp, sizeof(int), 1, grid_in);

    avdw = new float[size];
    bvdw = new float[size];
    es = new float[size];

    fread((void *) bvdw, sizeof(float), size, grid_in);
    fread((void *) avdw, sizeof(float), size, grid_in);
    fread((void *) es, sizeof(float), size, grid_in);


    fclose(grid_in);

}

/************************************************/
// Read in the occupancy desolvation grid kxr 1205
void
Chemgrid_Grid::read_odm_grid()
{
    string          fname;
    int             i,
                    j;

    fname = file_prefix + ".dsl";
    grid_in = fopen(fname.c_str(), "rb");

    if (grid_in == NULL) {
        cout << "\n\nCould not open " << fname <<
            " for reading.  Program will terminate." << endl << endl;
        exit(0);
    }

    cout << " Reading occupancy desolvation grid from " << fname << endl;

    fread(&size, sizeof(int), 1, grid_in);
    fread(&spacing, sizeof(float), 1, grid_in);
    fread(origin, sizeof(float), 3, grid_in);
    fread(span, sizeof(int), 3, grid_in);

    // dslb = (float *)malloc(size * sizeof(float));
    // dslx = (float *)malloc(size * sizeof(float));
    dslb = new float[size];
    dslx = new float[size];

    fread((void *) dslb, sizeof(float), size, grid_in);
    fread((void *) dslx, sizeof(float), size, grid_in);


    fclose(grid_in);

}


/************************************************/
void
Chemgrid_Grid::read_phi_grid()
{
    // Read in rec. phimap generated by Delphi -- kxr 0305

    int             i,
                    j,
                    k,
                    l;
    string          fname;

    fname = file_prefix + ".phi";
    grid_in = fopen(fname.c_str(), "rb");

    if (grid_in == NULL) {
        cout << "\n\nCould not open phimap " << fname <<
            " for reading.  Program will terminate." << endl << endl;
        exit(0);
    }

    cout << " Reading DelPhi grid from " << fname << endl;

    fread(&dsize, sizeof(int), 1, grid_in);
    fread(&dspacing, sizeof(float), 1, grid_in);
    fread(oldmid, sizeof(float), 3, grid_in);
    fread(dspan, sizeof(int), 3, grid_in);

    // phi = (float *)malloc(dsize * sizeof(float));
    phi = new float[dsize];
    fread((void *) phi, sizeof(float), dsize, grid_in);

    fclose(grid_in);


    l = 0;
    for (i = 0; i < dspan[0]; ++i) {
        for (j = 0; j < dspan[1]; ++j) {
            for (k = 0; k < dspan[2]; ++k) {
                phimap[i][j][k] = phi[l];
                l++;
            }
        }
    }


}


/*****************************************************/
void
Chemgrid_Grid::read_solv_grid()
{
    // Solvent Occlusion Grid reading and calculation
    // capability incorporated in DOCK 5.2. Code adapted
    // from dock 3.5.54 by BKS
    // kxr 050205 


    string          fname,
                    tmp;
    char            line[100];
    int             i,
                    j,
                    k,
                    l,
                    kk,
                    start;
    int             cadif1,
                    cadif2,
                    cadif3;

    fname = solv_file_prefix;
    solv_grid_in = fopen(fname.c_str(), "rb");

    if (solv_grid_in == NULL) {
        cout << "\n\nCould not open " << fname << endl;
        exit(0);
    }

    cout << " Reading ligand desolvation grid from " << fname << endl;

    l = 0;
    while (fgets(line, 100, solv_grid_in) != NULL) {
        if (l == 0) {
            sscanf(line, "%i %i %i %i %i %i %i", &cadif1, &cadif2, &cadif3,
                   &perang, &solv_grd_ex[0], &solv_grd_ex[1], &solv_grd_ex[2]);
            l++;
            if (cadif1 > MAXDIX || cadif2 > MAXDIY || cadif3 > MAXDIZ) {
                cout <<
                    "\n\n Memory bounds exceeded for solvent occlusion grid.";
                cout << " Program will terminate." << endl;
                exit(0);
            }
        } else {
            for (i = 0; i <= cadif1; i++) {
                for (j = 0; j <= cadif2; j++) {
                    for (k = 0; k <= cadif3; k = k + 13) {
                        l++;
                        if (k + 12 <= cadif3) {
                            if (l > 2)
                                fgets(line, 100, solv_grid_in);
                            tmp = line;
                            start = 0;
                            for (kk = k; kk <= k + 12; kk++) {
                                solvgrd[i][j][kk] =
                                    atof(tmp.substr(start, 6).c_str());
                                start = start + 6;
                            }
                        } else {
                            if (l > 2)
                                fgets(line, 100, solv_grid_in);
                            tmp = line;
                            start = 0;
                            for (kk = k; kk <= cadif3; kk++) {
                                solvgrd[i][j][kk] =
                                    atof(tmp.substr(start, 6).c_str());
                                start = start + 6;
                            }
                        }
                    }
                }
            }
        }
    }

    fclose(solv_grid_in);
}

/************************************************/
// receptor desolvation grid calculated using DelPhi kxr 0306
void
Chemgrid_Grid::read_rdsol_grid()
{

    string          fname;
    string          tmp;
    char            line[100];
    char            cgrid;
    int             cadif1,
                    cadif2,
                    cadif3;
    int             nlist,
                    sumlst;
    int             i,
                    j,
                    k,
                    l;
    float           ascore;


    fname = file_prefix + ".rdl";
    rdsol_grid_in = fopen(fname.c_str(), "rb");

    if (rdsol_grid_in == NULL) {
        cout << "\n\nCould not open " << fname <<
            " for reading.  Program will terminate." << endl << endl;
        exit(0);
    }

    cout << " Reading receptor desolvation grid from " << fname << endl;


    l = 0;
    sumlst = 0;
    while (fgets(line, 100, rdsol_grid_in) != NULL) {
        if (l == 0) {
            sscanf(line, "%i %i %i %i %i %i %i", &cadif1, &cadif2, &cadif3, &rdgrdiv, &rdxmax, &rdymax, &rdzmax);       // first 
                                                                                                                        // line 
                                                                                                                        // read 
                                                                                                                        // grid 
                                                                                                                        // params 
                                                                                                                        // kxr
            l++;
            // Check memory bounds
            if (cadif1 > MAXDIX || cadif2 > MAXDIY || cadif3 > MAXDIZ) {
                cout <<
                    "\n\n Memory bounds exceeded in desolvation grid. Program will Terminate"
                    << endl;
                exit(0);
            }
        } else {
            for (i = 0; i < cadif1 + 1; ++i) {
                for (j = 0; j < cadif2 + 1; ++j) {
                    while (sumlst < cadif3 + 1) {
                        l++;
                        if (l > 2)
                          fgets(line, 100, rdsol_grid_in);  // readmap
                        tmp = line;
                        nlist = atoi(tmp.substr(0, 4).c_str());
                        ascore = atof(tmp.substr(4, 10).c_str());
                        for (k = sumlst; k < sumlst + nlist; ++k) {
                            if (ascore == 128.0)
                                rdsol[i][j][k] = 0.0;
                            else
                                rdsol[i][j][k] = ascore;
                        }
                        sumlst = sumlst + nlist;
                    }
                    sumlst = 0;
                }
            }
        }


    }
    fclose(rdsol_grid_in);

}
// +++++++++++++++++++++++++++++++++++++++++
// replicate grid interpolation for looking up phi
// values for electrostatic kxr
void
Chemgrid_Grid::phi_corner_coords()
{
    float           dx,
                    dy,
                    dz;

    dx = (dspan[0]) * dspacing;
    dy = (dspan[1]) * dspacing;
    dz = (dspan[2]) * dspacing;

    phi_origin[0] = oldmid[0] - ((dspan[0] - 1) / 2) * dspacing;
    phi_origin[1] = oldmid[1] - ((dspan[1] - 1) / 2) * dspacing;
    phi_origin[2] = oldmid[2] - ((dspan[2] - 1) / 2) * dspacing;

    phi_x_min = phi_origin[0];
    phi_x_max = phi_origin[0] + dx;
    phi_y_min = phi_origin[1];
    phi_y_max = phi_origin[1] + dy;
    phi_z_min = phi_origin[2];
    phi_z_max = phi_origin[2] + dz;

    phi_corners[0].assign_vals(phi_x_min, phi_y_min, phi_z_min);
    phi_corners[1].assign_vals(phi_x_max, phi_y_min, phi_z_min);
    phi_corners[2].assign_vals(phi_x_max, phi_y_min, phi_z_max);
    phi_corners[3].assign_vals(phi_x_min, phi_y_min, phi_z_max);
    phi_corners[4].assign_vals(phi_x_min, phi_y_max, phi_z_min);
    phi_corners[5].assign_vals(phi_x_max, phi_y_max, phi_z_min);
    phi_corners[6].assign_vals(phi_x_max, phi_y_max, phi_z_max);
    phi_corners[7].assign_vals(phi_x_min, phi_y_max, phi_z_max);
}

// +++++++++++++++++++++++++++++++++++++++++
// kxr 
bool
Chemgrid_Grid::phi_box_boundaries(float x, float y, float z)
{
    // return true if the x,y,z point is inside the phi box.
    return ! ((x < phi_x_min) || (x >= phi_x_max) ||
              (y < phi_y_min) || (y >= phi_y_max) ||
              (z < phi_z_min) || (z >= phi_z_max)) ;
}

// +++++++++++++++++++++++++++++++++++++++++
void
Chemgrid_Grid::find_phi_neighbors(float x, float y, float z)
{
    int             phi_x_below,
                    phi_x_above;
    int             phi_y_below,
                    phi_y_above;
    int             phi_z_below,
                    phi_z_above;
    int             phi_x_nearest,
                    phi_y_nearest,
                    phi_z_nearest;
    float           phi_x_int,
                    phi_y_int,
                    phi_z_int;
    float           corrected_coords[3];

    phi_x_int = x - phi_origin[0];
    phi_y_int = y - phi_origin[1];
    phi_z_int = z - phi_origin[2];

    phi_x_nearest = NINT(phi_x_int / dspacing);
    phi_x_below = INTFLOOR(phi_x_int / dspacing);
    // x_below = (int)floor(x_int/spacing);
    phi_x_above = phi_x_below + 1;
    if (phi_x_nearest >= dspan[0]) {
        if (phi_x_below >= dspan[0])
            phi_x_nearest = dspan[0] - 1;
        else
            phi_x_nearest = phi_x_below;
    }
    if (phi_x_nearest < 0) {
        if (phi_x_above < 0)
            phi_x_nearest = 0;
        else
            phi_x_nearest = phi_x_above;
    }

    phi_y_nearest = NINT(phi_y_int / dspacing);
    phi_y_below = INTFLOOR(phi_y_int / dspacing);
    // y_below = (int)floor(y_int/spacing);
    phi_y_above = phi_y_below + 1;
    if (phi_y_nearest >= dspan[1]) {
        if (phi_y_below >= dspan[1])
            phi_y_nearest = dspan[1] - 1;
        else
            phi_y_nearest = phi_y_below;
    }
    if (phi_y_nearest < 0) {
        if (phi_y_above < 0)
            phi_y_nearest = 0;
        else
            phi_y_nearest = phi_y_above;
    }

    phi_z_nearest = NINT(phi_z_int / dspacing);
    phi_z_below = INTFLOOR(phi_z_int / dspacing);
    // z_below = (int)floor(z_int/spacing);
    phi_z_above = phi_z_below + 1;
    if (phi_z_nearest >= dspan[2]) {
        if (phi_z_below >= dspan[2])
            phi_z_nearest = dspan[2] - 1;
        else
            phi_z_nearest = phi_z_below;
    }
    if (phi_z_nearest < 0) {
        if (phi_z_above < 0)
            phi_z_nearest = 0;
        else
            phi_z_nearest = phi_z_above;
    }

    phi_nearest_neighbor =
        find_phi_index(phi_x_nearest, phi_y_nearest, phi_z_nearest);

    phi_neighbors[0] = find_phi_index(phi_x_above, phi_y_above, phi_z_above);
    phi_neighbors[1] = find_phi_index(phi_x_above, phi_y_above, phi_z_below);
    phi_neighbors[2] = find_phi_index(phi_x_above, phi_y_below, phi_z_above);
    phi_neighbors[3] = find_phi_index(phi_x_below, phi_y_above, phi_z_above);
    phi_neighbors[4] = find_phi_index(phi_x_above, phi_y_below, phi_z_below);
    phi_neighbors[5] = find_phi_index(phi_x_below, phi_y_above, phi_z_below);
    phi_neighbors[6] = find_phi_index(phi_x_below, phi_y_below, phi_z_above);
    phi_neighbors[7] = find_phi_index(phi_x_below, phi_y_below, phi_z_below);

    corrected_coords[0] = x - phi_origin[0];
    corrected_coords[1] = y - phi_origin[1];
    corrected_coords[2] = z - phi_origin[2];

    phi_int_coords[0] = corrected_coords[0];
    phi_int_coords[1] = corrected_coords[1];
    phi_int_coords[2] = corrected_coords[2];

    phi_cube_coords[0] = corrected_coords[0] / dspacing - (float) (INTFLOOR(corrected_coords[0] / dspacing));   // removed 
                                                                                                                // (int)
    phi_cube_coords[1] = corrected_coords[1] / dspacing - (float) (INTFLOOR(corrected_coords[1] / dspacing));   // removed 
                                                                                                                // (int)
    phi_cube_coords[2] = corrected_coords[2] / dspacing - (float) (INTFLOOR(corrected_coords[2] / dspacing));   // removed 
                                                                                                                // (int)
}
// +++++++++++++++++++++++++++++++++++++++++
int
Chemgrid_Grid::find_phi_index(int x, int y, int z)
{
    return dspan[0] * dspan[1] * z + dspan[0] * y + x;
}

// +++++++++++++++++++++++++++++++++++++++++
float
Chemgrid_Grid::interpolphi(float *pgrid)
{
    double          a1,
                    a2,
                    a3,
                    a4,
                    a5,
                    a6,
                    a7,
                    a8;
    double          value;
    int             out_of_bounds,
                    i;

    out_of_bounds = 0;
    for (i = 0; i < 8; i++)
        if ((phi_neighbors[i] > dsize) || (phi_neighbors[i] < 0))
            out_of_bounds = 1;

    if (out_of_bounds == 0) {
        a8 = pgrid[phi_neighbors[7] - 1];
        a7 = pgrid[phi_neighbors[6] - 1] - a8;
        a6 = pgrid[phi_neighbors[5] - 1] - a8;
        a5 = pgrid[phi_neighbors[4] - 1] - a8;
        a4 = pgrid[phi_neighbors[3] - 1] - a8 - a7 - a6;
        a3 = pgrid[phi_neighbors[2] - 1] - a8 - a7 - a5;
        a2 = pgrid[phi_neighbors[1] - 1] - a8 - a6 - a5;
        a1 = pgrid[phi_neighbors[0] - 1] - a8 - a7 - a6 - a5 - a4 - a3 - a2;

        // printf("%8.3f%8.3f%8.3f%8.3f%8.3f%8.3f%8.3f%8.3f\n",
        // a1,a2,a3,a4,a5,a6,a7,a8);

        value =
            a1 * phi_cube_coords[0] * phi_cube_coords[1] * phi_cube_coords[2] +
            a2 * phi_cube_coords[0] * phi_cube_coords[1] +
            a3 * phi_cube_coords[0] * phi_cube_coords[2] +
            a4 * phi_cube_coords[1] * phi_cube_coords[2] +
            a5 * phi_cube_coords[0] + a6 * phi_cube_coords[1] +
            a7 * phi_cube_coords[2] + a8;


        return value;
    } else {
        return pgrid[phi_nearest_neighbor];
    }

}

/*********************************************************
	kxr 042205
	The following is an alternate implementation
	of the interpolation code for the DelPhi phimap.
	
	The basic steps for calculating the electrostatic 
	potential on the ligand atom are 
		1) converting real space coordinates of the ligand 
		   atom to grid coordinates. this is done in 
		   real_to_phi_coords function
		2) Then the potential is calculated by trilinear
		   interpolation. the converted grid coordinates
		   phi_coords are changed to integer values as
					nx = int(phi_space)
		3) These integer numbers serve as lookup values 
		   in the phimap as
		   a8 = phimap[nx][ny][nz]
		4) However before this step, 1 needs to be substracted
		   from nx, ny and nz because in the fortran generated
		   DelPhi grid the grid points indices start at 1,1,1 
		   where as in C++ it starts at 0,0,0. Just a matter of 
		   bookkeeping. 
********************************************************/

/*******************************************************/
void
Chemgrid_Grid::real_to_phi_coords(float x, float y, float z)
{
    float           goff;

    goff = (float (dspan[0]) + 1.0) /2.0;
    phi_space[0] = (x - oldmid[0]) * dspacing + goff;
    phi_space[1] = (y - oldmid[1]) * dspacing + goff;
    phi_space[2] = (z - oldmid[2]) * dspacing + goff;

}

/***********************************************/
float
Chemgrid_Grid::interpolpot()
{
    int             i;
    int             nx,
                    ny,
                    nz;
    float           rgrid;
    float           phi_value;
    float           xgr,
                    ygr,
                    zgr;
    float           a1,
                    a2,
                    a3,
                    a4,
                    a5,
                    a6,
                    a7,
                    a8;

    rgrid = float   (dspan[0] - 1);
    for (i = 0; i <= 2; i++)
        if (phi_space[i] < 1 || phi_space[i] > rgrid) {
            phi_value = 0.0;    // return 0.0 if outside grid_in
            return phi_value;
        }


    nx = int        (phi_space[0]);
    ny = int        (phi_space[1]);
    nz = int        (phi_space[2]);


    if (nx > dspan[0] || ny > dspan[1] || nz > dspan[2]) {
        cout << " Array bounds exceeded for phimap" << endl;
        exit(0);
    }


    xgr = phi_space[0] - float (nx);
    ygr = phi_space[1] - float (ny);
    zgr = phi_space[2] - float (nz);


    nx = nx - 1;
    ny = ny - 1;
    nz = nz - 1;

    a8 = phimap[nx][ny][nz];
    a7 = phimap[nx][ny][nz + 1] - a8;
    a6 = phimap[nx][ny + 1][nz] - a8;
    a5 = phimap[nx + 1][ny][nz] - a8;
    a4 = phimap[nx][ny + 1][nz + 1] - a8 - a7 - a6;
    a3 = phimap[nx + 1][ny][nz + 1] - a8 - a7 - a5;
    a2 = phimap[nx + 1][ny + 1][nz] - a8 - a6 - a5;
    a1 = phimap[nx + 1][ny + 1][nz + 1] - a8 - a7 - a6 - a5 - a4 - a3 - a2;

    // printf("%8.3f%8.3f%8.3f%8.3f%8.3f%8.3f%8.3f%8.3f\n",
    // a1,a2,a3,a4,a5,a6,a7,a8);

    phi_value = a1 * xgr * ygr * zgr + a2 * xgr * ygr + a3 * xgr * zgr
        + a4 * ygr * zgr + a5 * xgr + a6 * ygr + a7 * zgr + a8;

    return phi_value;
}

// +++++++++++++++++++++++++++++++++++++++++
float
Chemgrid_Score::get_atom_shape_score(float x, float y, float z)
{
    // Only for debugging but could be useful. kxr
    float           atomic_shape_score;
    int             tmp = 0;
    int             lx,
                    ly,
                    lz;

    lx = shape.xmax - NINT(x * shape.grddiv);
    if ((lx >= 0) && (lx <= MAXDIX)) {
        ly = shape.ymax - NINT(y * shape.grddiv);
        if ((ly >= 0) && (ly <= MAXDIY)) {
            lz = shape.zmax - NINT(z * shape.grddiv);
            if ((lz >= 0) && (lz <= MAXDIZ)) {
// srb feb 27 2008; see the cvs log for more details.
// score_chemgrid.cpp:1112: error: no match for ‘operator[]’ in ‘((Chemgrid_Score*)this)->Chemgrid_Score::shape[lx]’
                //tmp = shape[lx][ly][lz];
                if (tmp < 0) {
                    tmp += 128;
                }
                atomic_shape_score = float (tmp);
            } else
                return -1;
        } else
            return -1;
    } else
        return -1;

    return atomic_shape_score;

}

/***********************************************************/
// Buried fraction calculation expt. code kxr
float
Chemgrid_Score::compute_buried_fraction(DOCKMol & mol)
{

    float           buried_fraction = 0.0f;
    unsigned int    N_buried = 0;
    unsigned int    N_heavy = 0;
    unsigned int    atom;
    float           vdw_att = 0.0f;

    for (atom = 0; atom < mol.num_atoms; atom++) {
        if (mol.amber_at_heavy_flag[atom] && mol.atom_active_flags[atom]) {
            if (chem_grid->is_inside_grid_box(mol.x[atom], mol.y[atom], mol.z[atom])) {
                chem_grid->find_grid_neighbors(mol.x[atom], mol.y[atom], mol.z[atom]);
                vdw_att = -vdwB[mol.amber_at_id[atom]] * chem_grid->interpolate(chem_grid->bvdw);
                if (vdw_att < -1.0f)
                    N_buried++;
                N_heavy++;
            }
        }
    }

    buried_fraction = float (N_buried) / float (N_heavy);
    return buried_fraction;
}

/***********************************************************/
// Atom buriedness kxr
bool
Chemgrid_Score::atom_buried(DOCKMol & mol, int atom_id)
{

    unsigned int    N_buried = 0;
    float           vdw_att = 0.0f;

    if (chem_grid->is_inside_grid_box(mol.x[atom_id], mol.y[atom_id], mol.z[atom_id])) {
        chem_grid->find_grid_neighbors(mol.x[atom_id], mol.y[atom_id], mol.z[atom_id]);
        vdw_att = -vdwB[mol.amber_at_id[atom_id]] * chem_grid->interpolate(chem_grid->bvdw);
        // cout << "vdw_att" << vdw_att << endl;
        if (vdw_att < -10.0f)
            return true;
    }
    return false;
}

/******************************************************/
// redistribute positive partial atomic desolvation kxr
// adapted from BKS redist. code from dock3.5.54 
bool
Chemgrid_Score::redist_positve_desolv(DOCKMol & mol)
{
    float           totpos,
                    totneg,
                    totsol;
    float           polsolv;
    unsigned int    atom;

    totpos = totneg = totsol = 0.0;
    for (atom = 0; atom < mol.num_atoms; atom++) {

        if (mol.atom_active_flags[atom]) {
            polsolv = mol.atom_psol[atom];
            if (polsolv > 0.0f) {
                totpos += polsolv;
                mol.atom_psol[atom] = 0.0f;
            } else
                totneg += polsolv;
        }
    }

    for (atom = 0; atom < mol.num_atoms; atom++) {
        if (mol.atom_active_flags[atom]) {
            polsolv = mol.atom_psol[atom];
            if (mol.atom_psol[atom] < 0.0f)
                mol.atom_psol[atom] += (totpos * polsolv) / totneg;
            totsol += mol.atom_psol[atom];
        }
    }

    return true;

}

